mapper.select:
SELECT u.usr_id, u.usr_nm, u.email, u.phone, u.dept_nm, u.role_cd, u.use_yn, u.pwd_chg_dt, u.last_login_dt, u.login_fail_cnt, u.lock_yn, u.created_at, u.created_by, u.updated_at, u.updated_by, c.code_nm AS role_nm FROM usr u LEFT JOIN com_code c ON c.grp_cd = 'USR_ROLE' AND c.code = u.role_cd
AND (u.usr_id LIKE CONCAT('%', #{searchKeyword}, '%') OR u.usr_nm LIKE CONCAT('%', #{searchKeyword}, '%') OR u.email LIKE CONCAT('%', #{searchKeyword}, '%'))
AND u.role_cd = #{searchRoleCd}
AND u.use_yn = #{searchUseYn}
ORDER BY u.created_at DESC
